import requests
from urllib.parse import urlparse
import logging

def fetch_url(url):
    try:
        response = requests.get(url, timeout=5)
        if response.status_code == 200:
            return response.text
        else:
            logging.error(f"Failed to retrieve URL: {url}. Status code: {response.status_code}")
            return None
    except requests.exceptions.RequestException as e:
        logging.error(f"Error fetching URL: {url}. Error: {e}")
        return None

def main():
    url = input("Enter the URL you want to fetch: ")
    if urlparse(url).scheme in ['http', 'https']:
        content = fetch_url(url)
        print(content)
    else:
        logging.error(f"Invalid URL scheme. Only HTTP and HTTPS are supported.")

if __name__ == "__main__":
    main()